                    gradient.addColorStop(0, '#4ecca3');
                    gradient.addColorStop(1, '#38b28a');
                    ctx.fillStyle = gradient;
                    roundRect(seg.x * GRID_SIZE + 1, seg.y * GRID_SIZE + 1, GRID_SIZE - 2, GRID_SIZE - 2, 5);

                    // Eyes
