                    let eyeOffX1, eyeOffY1, eyeOffX2, eyeOffY2;
                    if (direction.x === 1) {
                        eyeOffX1 = 12; eyeOffY1 = 5; eyeOffX2 = 12; eyeOffY2 = 13;
                    } else if (direction.x === -1) {
                        eyeOffX1 = 6; eyeOffY1 = 5; eyeOffX2 = 6; eyeOffY2 = 13;
                    } else if (direction.y === -1) {
                        eyeOffX1 = 5; eyeOffY1 = 6; eyeOffX2 = 13; eyeOffY2 = 6;
                    } else {
                        eyeOffX1 = 5; eyeOffY1 = 12; eyeOffX2 = 13; eyeOffY2 = 12;
                    }
                    ctx.beginPath();
                    ctx.arc(seg.x * GRID_SIZE + eyeOffX1, seg.y * GRID_SIZE + eyeOffY1, 2.5, 0, Math.PI * 2);
                    ctx.fill();
                    ctx.beginPath();
                    ctx.arc(seg.x * GRID_SIZE + eyeOffX2, seg.y * GRID_SIZE + eyeOffY2, 2.5, 0, Math.PI * 2);
