                    ctx.arc(seg.x * GRID_SIZE + eyeOffX1 + direction.x, seg.y * GRID_SIZE + eyeOffY1 + direction.y, 1.2, 0, Math.PI * 2);
                    ctx.fill();
                    ctx.beginPath();
                    ctx.arc(seg.x * GRID_SIZE + eyeOffX2 + direction.x, seg.y * GRID_SIZE + eyeOffY2 + direction.y, 1.2, 0, Math.PI * 2);
                    ctx.fill();
                } else {
                    const r = Math.floor(78 - t * 40);
                    const g = Math.floor(204 - t * 80);
                    const b = Math.floor(163 - t * 60);
                    ctx.fillStyle = `rgb(${r},${g},${b})`;
                    roundRect(seg.x * GRID_SIZE + 1.5, seg.y * GRID_SIZE + 1.5, GRID_SIZE - 3, GRID_SIZE - 3, 4);
