            ctx.fillStyle = 'rgba(0,0,0,0.7)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.fillStyle = '#4ecca3';
            ctx.font = 'bold 48px Arial';
            ctx.textAlign = 'center';
            ctx.fillText('贪食蛇', canvas.width / 2, 200);

            // Snake icon
            ctx.font = '80px Arial';
            ctx.fillText('🐍', canvas.width / 2, 320);

            ctx.fillStyle = '#fff';
            ctx.font = '18px Arial';
            ctx.fillText('点击屏幕或按空格开始', canvas.width / 2, 420);

            ctx.fillStyle = '#aaa';
            ctx.font = '14px Arial';
            ctx.fillText('↑↓←→ 或 WASD 控制方向', canvas.width / 2, 460);
            ctx.fillText('也可以滑动屏幕控制', canvas.width / 2, 485);

            if (highScore > 0) {
                ctx.fillStyle = '#ffd700';
                ctx.font = '16px Arial';
                ctx.fillText(`最高分: ${highScore}`, canvas.width / 2, 540);
            }
        }

        function drawGameOver() {
            ctx.fillStyle = 'rgba(0,0,0,0.75)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.fillStyle = '#e94560';
            ctx.font = 'bold 42px Arial';
            ctx.textAlign = 'center';
            ctx.fillText('游戏结束', canvas.width / 2, 230);

            ctx.fillStyle = '#fff';
            ctx.font = '24px Arial';
            ctx.fillText(`得分: ${score}`, canvas.width / 2, 300);

            if (score >= highScore && score > 0) {
                ctx.fillStyle = '#ffd700';
                ctx.font = 'bold 20px Arial';
                ctx.fillText('🎉 新纪录! 🎉', canvas.width / 2, 345);
            }

            ctx.fillStyle = '#4ecca3';
            ctx.font = '18px Arial';
            ctx.fillText(`最高分: ${highScore}`, canvas.width / 2, 390);

            ctx.fillStyle = '#aaa';
            ctx.font = '16px Arial';
            ctx.fillText('点击或按空格重新开始', canvas.width / 2, 450);
        }

        function update() {
            direction = { ...nextDirection };

            const head = { x: snake[0].x + direction.x, y: snake[0].y + direction.y };

            // Wall collision
            if (head.x < 0 || head.x >= COLS || head.y < 0 || head.y >= ROWS) {
                gameOver();
                return;
            }

            // Self collision
            for (let i = 0; i < snake.length; i++) {
                if (head.x === snake[i].x && head.y === snake[i].y) {
                    gameOver();
                    return;
                }
            }

            snake.unshift(head);

            // Food collision
            if (head.x === food.x && head.y === food.y) {
                const points = food.type === 'golden' ? 30 : 10;
                score += points;
                const particleColor = food.type === 'golden' ? '#ffd700' : '#e94560';
                createParticles(food.x, food.y, particleColor, 15);

                if (food.type === 'golden') {
                    createParticles(food.x, food.y, '#fff7a1', 10);
                }

                spawnFood();

                // Increase speed
                speed = Math.max(50, 120 - Math.floor(score / 50) * 8);
            } else {
                snake.pop();
            }
        }

        function gameOver() {
            gameState = 'gameover';
            if (score > highScore) {
                highScore = score;
                localStorage.setItem('snakeHighScore', highScore);
            }
            // Death particles
            for (let seg of snake) {
                createParticles(seg.x, seg.y, '#e94560', 3);
            }
        }

        // Input handling
        let touchStartX, touchStartY;

        document.addEventListener('keydown', (e) => {
            if (gameState === 'start' || gameState === 'gameover') {
                if (e.code === 'Space' || e.code === 'Enter') {
                    init();
                    return;
                }
            }

            if (gameState !== 'playing') return;

            switch (e.key) {
                case 'ArrowUp': case 'w': case 'W':
                    if (direction.y !== 1) nextDirection = { x: 0, y: -1 };
                    break;
                case 'ArrowDown': case 's': case 'S':
                    if (direction.y !== -1) nextDirection = { x: 0, y: 1 };
                    break;
                case 'ArrowLeft': case 'a': case 'A':
                    if (direction.x !== 1) nextDirection = { x: -1, y: 0 };
                    break;
                case 'ArrowRight': case 'd': case 'D':
                    if (direction.x !== -1) nextDirection = { x: 1, y: 0 };
                    break;
            }
            e.preventDefault();
        });

        canvas.addEventListener('touchstart', (e) => {
            e.preventDefault();
            if (gameState === 'start' || gameState === 'gameover') {
                init();
                return;
            }
            touchStartX = e.touches[0].clientX;
            touchStartY = e.touches[0].clientY;
        }, { passive: false });

        canvas.addEventListener('touchmove', (e) => {
            e.preventDefault();
        }, { passive: false });

        canvas.addEventListener('touchend', (e) => {
            e.preventDefault();
            if (gameState !== 'playing' || !touchStartX) return;

            const touchEndX = e.changedTouches[0].clientX;
            const touchEndY = e.changedTouches[0].clientY;
            const dx = touchEndX - touchStartX;
            const dy = touchEndY - touchStartY;

            const minSwipe = 20;

            if (Math.abs(dx) < minSwipe && Math.abs(dy) < minSwipe) return;

            if (Math.abs(dx) > Math.abs(dy)) {
                if (dx > 0 && direction.x !== -1) nextDirection = { x: 1, y: 0 };
                else if (dx < 0 && direction.x !== 1) nextDirection = { x: -1, y: 0 };
            } else {
                if (dy > 0 && direction.y !== -1) nextDirection = { x: 0, y: 1 };
                else if (dy < 0 && direction.y !== 1) nextDirection = { x: 0, y: -1 };
            }
        }, { passive: false });

        canvas.addEventListener('click', () => {
            if (gameState === 'start' || gameState === 'gameover') {
                init();
            }
        });

        // Game loop
        gameState = 'start';
        let lastTime = 0;
        let accumulator = 0;

        function gameLoop(timestamp) {
            const deltaTime = timestamp - lastTime;
            lastTime = timestamp;

            if (gameState === 'start') {
                drawStartScreen();
            } else if (gameState === 'playing') {
                accumulator += deltaTime;
                if (accumulator >= speed) {
                    update();
                    accumulator = 0;
                }
                updateParticles();
                drawGrid();
                drawFood();
                drawSnake();
                drawParticles();
                drawScore();
            } else if (gameState === 'gameover') {
                updateParticles();
                drawGrid();
                drawSnake();
                drawParticles();
                drawScore();
                drawGameOver();
            }

            requestAnimationFrame(gameLoop);
        }

        requestAnimationFrame(gameLoop);
    </script>
</body>
</html>
